import colorsJson from "./colors.json";

export const colors = colorsJson;

export const getColorChart = (name, alpha = 255) => {
  alpha = parseInt(alpha);
  if (alpha == NaN) {
    alpha = 255;
  }
  if (alpha < 16) {
    alpha = 16;
  }
  if (alpha > 255) {
    alpha = 255;
  }
  return `${colors[name]}${alpha.toString(16)}`.toUpperCase();
};
