<template>
  <b-form @submit.prevent.stop="onSubmit">
    <h1>Quiz</h1>
    <b-form-group label="Amount">
      <b-form-input
        type="number"
        v-model.number="$v.form.amount.$model"
        :state="validateState('amount')"
      ></b-form-input>
      <b-form-invalid-feedback>
        Amount of quest must between 1 and 50.
      </b-form-invalid-feedback>
    </b-form-group>
    <b-form-group label="Category">
      <b-form-select v-model="form.category">
        <b-form-select-option :value="null">
          Any
        </b-form-select-option>
        <b-form-select-option
          v-for="category in categories"
          :key="category.value"
          :value="category.value"
        >
          {{ category.text }}
        </b-form-select-option>
      </b-form-select>
    </b-form-group>
    <b-form-group label="Difficulty">
      <b-form-select
        v-model="form.difficulty"
        :options="difficultyOptions"
      ></b-form-select>
    </b-form-group>
    <b-form-group label="Type">
      <b-form-select v-model="form.type" :options="typeOptions"></b-form-select>
    </b-form-group>
    <b-form-group>
      <b-button type="submit" variant="primary" block>Submit</b-button>
    </b-form-group>
  </b-form>
</template>

<script>
import axios from "axios";
import { required, between } from "vuelidate/lib/validators";
import ExamsService from "@/services/ExamsService";

export default {
  name: "Home",
  data() {
    return {
      categories: [],
      difficultyOptions: [
        { value: null, text: "Any" },
        { value: "easy", text: "Easy" },
        { value: "medium", text: "Medium" },
        { value: "hard", text: "Hard" },
      ],
      typeOptions: [
        { value: null, text: "Any" },
        { value: "multiple", text: "Multiple Choice" },
        { value: "boolean", text: "True/False" },
      ],
      form: {
        category: null,
        amount: 5,
        difficulty: null,
        type: null,
      },
    };
  },
  validations: {
    form: {
      amount: {
        between: between(1, 50),
      },
    },
  },
  mounted() {
    this.fetchCategories();
  },
  methods: {
    validateState(name) {
      const { $dirty, $error } = this.$v.form[name];
      return $dirty ? !$error : null;
    },
    onSubmit(event) {
      this.$v.form.$touch();
      if (this.$v.form.$anyError) {
        return;
      }
      ExamsService.post(this.form).then((response) => {
        const { id } = response.data;
        this.$router.push({ name: "Quiz", params: { id } });
      });
    },
    fetchCategories() {
      axios.get("https://opentdb.com/api_category.php").then((response) => {
        const { data } = response;
        this.categories = data.trivia_categories.map((item) => ({
          text: item.name,
          value: item.id,
        }));
      });
    },
  },
};
</script>

