import Vue from "vue";
import Vuex from "vuex";
import AccountService from '@/services/AccountService';

Vue.use(Vuex);

export default new Vuex.Store({
  state: {
    authenticationToken: localStorage.getItem('authentication'),
  },
  getters: {
    isAuthenticated: state => {
      return state.authenticationToken != null && state.authenticationToken.length > 0;
    },
    user: (state, getters) => {
      if (getters.isAuthenticated) {
        return JSON.parse(localStorage.getItem('user'));
      }
      return null;
    }
  },
  mutations: {
    updateAuthenticationToken(state, value) {
      state.authenticationToken = value;
    }
  },
  actions: {
    async authenticateHandle({ commit }, user) {
      try {
        var response = await AccountService.authenticate(user);
        console.log(response)
        var data = response.data;
        localStorage.setItem("user", JSON.stringify(data.user));
        localStorage.setItem('authentication', data.token);
        commit('updateAuthenticationToken', data.token);
        return { isAuthenticated: true };
      }
      catch (exception) {
        const { status, data } = exception.response;
        var message = "";
        switch (status) {
          case 422:
            data.errors.forEach((error) => {
              message += `${error.param}: ${error.msg}\n`;
            });
            break;
          case 403:
            message = data.message;
            break;
          case 400:
          default:
            message = "Something wrong.";
            break;
        };
        return { isAuthenticated: false, message };
      }
    },
    logoutHandle({ commit }) {
      localStorage.removeItem('user');
      localStorage.removeItem('authentication');
      commit('updateAuthenticationToken', null);
    }
  },
  modules: {}
});
