  name: "Test",

  components: {
    LineChart,
    BarChart,
    RadarChart,
    DoughnutChart,
    PieChart,
    ScatterChart,
  },

  data() {
    return {
      radarChartData: {
        labels: ["STR", "INT", "VIT", "PIE", "AGI", "LUK", "DEX"],
