        datasets: [
          {
            backgroundColor: [
              colors["primary"],
              colors["primary-light"],
              colors["primary-dark"],
              colors["secondary"],
              colors["secondary-light"],
              colors["secondary-dark"],
              colors["thirdary"],
              colors["thirdary-light"],
              colors["thirdary-dark"],
            ],
            data: [578, 2682, 726, 859, 990, 1348, 923],
          },
        ],
      },
      chartData: {
        labels: [
          "January",
          "February",
          "March",
          "April",
          "May",
          "June",
          "July",
        ],
        datasets: [
          {
            label: "Data One",
            backgroundColor: getColorChart("primary", 127),
            data: [40, 39, 10, 40, 39, 80, 40],
          },
          {
            label: "Data Two",
            backgroundColor: getColorChart("secondary", 127),
            data: [32, 11, 65, 98, 45, 66, 78],
          },
          {
            label: "Data Three",
            backgroundColor: getColorChart("thirdary", 127),
            data: [45, 22, 33, 44, 87, 98, 20],
          },
        ],
      },
      options: { responsive: true, maintainAspectRatio: false },
      scatterChartData: {
        datasets: [
          {
            label: "Scatter Dataset",
            data: [
              {
                x: -10,
                y: 0,
              },
              {
                x: 0,
                y: -10,
              },
              {
                x: 10,
                y: 5,
              },
              {
                x: 2,
                y: 2,
              },
            ],
          },
        ],
      },
      scatterOptions: {
        responsive: true,
        maintainAspectRatio: false,
      },
      date: "",
      time: "",
      index: 1,
      items: [],
      editor: ClassicEditor,
      editorData: "",
      editorConfig: {
        toolbar: {
          items: [
            "heading",
            "|",
            "bold",
            "italic",
            "underline",
            "link",
            "alignment",
            "fontBackgroundColor",
            "fontColor",
            "bulletedList",
            "numberedList",
            "|",
            "indent",
            "outdent",
            "|",
            "insertImage",
            "blockQuote",
            "insertTable",
            "mediaEmbed",
            "undo",
            "redo",
            "|",
            "codeBlock",
            "specialCharacters",
            "removeFormat",
          ],
        },
        language: "en",
        image: {
          toolbar: [
            "imageTextAlternative",
            "imageStyle:full",
            "imageStyle:side",
          ],
        },
        table: {
          contentToolbar: [
            "tableColumn",
            "tableRow",
            "mergeTableCells",
            "tableCellProperties",
            "tableProperties",
          ],
        },
      },
      editId: null,
    };
  },
  computed: {
    isInEditMode() {
      return this.editId !== null;
    },
  },
  methods: {
    loadOembed() {
      document.querySelectorAll("oembed[url]").forEach((element) => {
        console.log(element.innerHTML);
        if (element.innerHTML == "") {
          iframely.load(element, element.attributes.url.value);
        }
      });
    },
    submit() {
      if (this.isInEditMode) {
        var record = this.items.find((item) => item.id == this.editId);
        record.content = this.editorData;
        this.editId = null;
      } else {
        var item = { id: this.index, content: this.editorData };
        this.items.unshift(item);
        this.index++;
      }
      this.editorData = "";
      this.$nextTick(() => this.loadOembed());
    },
    edit(id) {
      var record = this.items.find((item) => item.id == id);
      this.editorData = record.content;
      this.editId = record.id;
    },
  },
};
</script>
