import Vue from "vue";
import VueRouter from "vue-router";
import Home from "@/views/Home.vue";
import Test from "@/views/Test.vue";
import Layout from "@/layouts/Layout.vue";

Vue.use(VueRouter);

const routes = [
  {
    path: "/",
    component: Layout,
    children: [
      {
        path: "",
        name: "Home",
        component: Home,
      },
      {
        path: "/test",
        name: "Test",
        component: Test,
      },
      {
        path: "/about",
        name: "About",
        component: () =>
          import(/* webpackChunkName: "about" */ "@/views/About.vue"),
      },
      {
        path: "/quiz/:id",
        name: "Quiz",
        component: () =>
          import(/* webpackChunkName: "about" */ "@/views/Quiz.vue"),
      },
      {
        path: "/register",
        name: "Register",
        component: () =>
          import(/* webpackChunkName: "account" */ "@/views/Register.vue"),
      },
      {
        path: "/login",
        name: "Login",
        component: () =>
          import(/* webpackChunkName: "account" */ "@/views/Login.vue"),
      },
    ],
  },
];

const router = new VueRouter({
  mode: "hash",
  base: process.env.BASE_URL,
  routes,
});

export default router;
